  { label: '미이수', value: 'I' },
];

// ─────────────────── State ──────────────────────────────────────────────────────────
const allRows = ref<RowItem[]>([...MOCK_DATA]);

const state = reactive({
  loading:     false,
  selectedRow: null as RowItem | null,
  pageSize:    20,
  page:        { first: 0, rows: 20 },
});

const searchParams = reactive({
  userId: '',
  userName: '',
  deptName: '',
  trainingDateRangeFrom: '',
  trainingDateRangeTo: '',
  completionStatus: '',
});

// ─────────────────── Computed ───────────────────────────────────────────────────────
const filteredRows = computed<RowItem[]>(() => {
  let rows = allRows.value;
  if (searchParams.userId) rows = rows.filter(r => r.userId.includes(searchParams.userId));
  if (searchParams.userName) rows = rows.filter(r => r.userName.includes(searchParams.userName));
  if (searchParams.deptName) rows = rows.filter(r => r.deptName.includes(searchParams.deptName));
  if (searchParams.trainingDateRangeFrom) rows = rows.filter(r => r.trainingDateRange >= searchParams.trainingDateRangeFrom);
  if (searchParams.trainingDateRangeTo)   rows = rows.filter(r => r.trainingDateRange <= searchParams.trainingDateRangeTo);
  if (searchParams.completionStatus) rows = rows.filter(r => r.completionStatus === searchParams.completionStatus);
  return rows;
});

const pagedRows = computed<RowItem[]>(() =>
  filteredRows.value.slice(state.page.first, state.page.first + state.pageSize)
);

// ─────────────────── Handlers ───────────────────────────────────────────────────────
